// Listenin aşırı şişmemesi için son 500 linki tutuyoruz
if (staticData.paylasilanlar.length > 500) {
  staticData.paylasilanlar.shift();
}

// Veriyi bir sonraki adıma (veya sona) aynen aktarıyoruz
return $json;

const allRows = $input.all().map(i => i.json);
const target = allRows.find(r => {
  const secim = (r.Secim || r.secim || r.SECIM || '').toString().toLowerCase().trim();
  const durum = (r.Durum || r.durum || r.DURUM || '').toString().toLowerCase().trim();
  return secim === 'evet' && durum !== 'tamam';
});
if (!target) return [];
return [{ json: {
  title: target.Baslik || target.baslik || '',
  article_url: target.URL || target.url || '',
  issue: target.Sayi || target.sayi || 'latest',
  row_number: String(target.No || target.no || '0')
}}];

const staticData = $getWorkflowStaticData('global');
staticData.ttsResults = [];
return [$input.first()];

const response = $input.first().json;
let cookies = '';
const sc = response.headers?.['set-cookie'];
if (Array.isArray(sc)) {
  cookies = sc.map(c => c.split(';')[0]).join('; ');
} else if (typeof sc === 'string') {
  cookies = sc.split(/,(?=[A-Za-z])/).map(c => c.split(';')[0].trim()).join('; ');
}
const body = typeof response.body === 'string' ? JSON.parse(response.body) : response.body;
if (!body || body.code !== 200) {
  throw new Error('Login basarisiz: ' + JSON.stringify(body));
}
return [{ json: { cookies } }];

const html = $input.first().json.data || '';
const info = $('Ilk Evet Bul').first().json;
const startIdx = html.indexOf('article-first-row');
if (startIdx < 0) {
  return [{ json: { title: info.title, article_text: '', char_count: 0 } }];
}
let section = html.substring(startIdx);
const endIdx = section.indexOf('article-tools-bottom');
if (endIdx > 0) section = section.substring(0, endIdx);
const paragraphs = [...section.matchAll(/<p[^>]*>([\s\S]*?)<\/p>/g)]
  .map(m => m[1].replace(/<[^>]+>/g, '')
    .replace(/&amp;/g,'&').replace(/&nbsp;/g,' ').replace(/&rsquo;/g,"'")
    .replace(/&ldquo;/g,'"').replace(/&rdquo;/g,'"').replace(/&ndash;/g,'-')
    .replace(/&mdash;/g,'-').replace(/&#039;/g,"'").replace(/&quot;/g,'"').trim())
  .filter(p => p.length > 30);
const articleText = paragraphs.join('\n\n');
return [{ json: { title: info.title, article_text: articleText, char_count: articleText.length } }];

const item = $input.first().json;
const config = $('Konfig').first().json;
if (!item.article_text || item.char_count < 100) {
  throw new Error('Makale icerigi cok kisa veya bos: ' + item.title);
}
const prompt = 'Sen bir Turkce podcast senaryo yazarisin. Asagidaki makaleyi 2 kisilik dogal bir podcast diyaloguna cevir.

Sunucular:
- AHMET: Ana sunucu, konuyu tanitan ve ozetleyen kisi
- EMEL: Yardimci sunucu, sorular soran, farkli perspektifler sunan kisi

Kurallar:
- Dogal konusma dilinde yaz, samimi ve akici bir ton kullan
- Makalenin onemli noktalarini koru
- Her konusmacinin sozlerini AHMET: veya EMEL: ile baslat
- 3-5 dakikalik podcast uzunlugunda yaz (800-1200 kelime)
- Turkce yaz
- Ilgi cekici giris ve ozet kapanis ekle

Makale Basligi: ' + item.title + '

Makale Metni:
' + item.article_text.substring(0, 15000) + '

Podcast senaryosunu yaz:';
const body = { contents: [{ parts: [{ text: prompt }] }], generationConfig: { temperature: 0.7, maxOutputTokens: 8192 } };
return [{ json: { gemini_key: config.gemini_key, gemini_body: JSON.stringify(body) } }];

const gemini = $input.first().json;
const info = $('Ilk Evet Bul').first().json;
let script = '';
try {
  script = gemini.candidates?.[0]?.content?.parts?.[0]?.text || '';
} catch(e) { script = ''; }
if (!script) {
  const err = gemini.error?.message || 'Gemini yanit vermedi';
  throw new Error(err);
}
return [{ json: { title: info.title, podcast_script: script, row_number: info.row_number } }];

const script = $input.first().json.podcast_script;
const lines = script.split('\n').filter(l => l.trim());
const segments = [];
for (const line of lines) {
  const m = line.match(/^\*{0,2}(AHMET|EMEL)\*{0,2}\s*:\s*(.*)/);
  if (m && m[2].trim().length > 0) {
    segments.push({
      speaker: m[1],
      text: m[2].replace(/\*+/g, '').trim(),
      voice: m[1] === 'AHMET' ? 'tr-TR-Chirp3-HD-Orus' : 'tr-TR-Chirp3-HD-Aoede',
      index: segments.length
    });
  }
}
if (segments.length === 0) {
  throw new Error('Senaryoda AHMET/EMEL segmentleri bulunamadi');
}
return segments.map(s => ({ json: s }));

const item = $input.first().json;
const body = {
  input: { text: item.text },
  voice: { languageCode: 'tr-TR', name: item.voice },
  audioConfig: { audioEncoding: 'MP3', speakingRate: 0.95, pitch: 0 }
};
return [{ json: { ttsBody: JSON.stringify(body), speaker: item.speaker, index: item.index } }];

const staticData = $getWorkflowStaticData('global');
if (!staticData.ttsResults) staticData.ttsResults = [];
staticData.ttsResults.push($input.first().json.audioContent);
return [$input.first()];

const staticData = $getWorkflowStaticData('global');
const results = staticData.ttsResults || [];
const info = $('Ilk Evet Bul').first().json;

if (results.length === 0) throw new Error('Hic TTS sonucu yok');

const buffers = results.map(ac => Buffer.from(ac, 'base64'));
const combined = Buffer.concat(buffers);

staticData.ttsResults = [];

const safeTitle = (info.title || 'podcast').replace(/[^a-zA-Z0-9\s-]/g, '').trim().substring(0, 50);
const fileName = 'HBR_Podcast_' + safeTitle + '.mp3';

return [{
  json: {
    title: info.title,
    fileName: fileName,
    row_number: info.row_number,
    audioSize: combined.length,
    segmentCount: results.length
  },
  binary: {
    audioFile: {
      data: combined.toString('base64'),
      mimeType: 'audio/mpeg',
      fileName: fileName,
      fileExtension: 'mp3'
    }
  }
}];

