const msg = $input.first().json.message;
const text = (msg.text || '').trim();
const sourceChatId = msg.chat.id;

if (!text.startsWith('/ilk11')) {
  return [{
    json: {
      ok: false,
      reason: 'Komut /ilk11 ile başlamalı.',
      sourceChatId
    }
  }];
}

const lines = text
  .split('\n')
  .slice(1)
  .map(l => l.trim())
  .filter(Boolean);

if (lines.length !== 11) {
  return [{
    json: {
      ok: false,
      reason: `Tam 11 oyuncu girmelisin. Şu an ${lines.length} satır var.`,
      sourceChatId
    }
  }];
}

const players = lines.map((line) => {
  const match = line.match(/^(\d{1,2})\s+(.+)$/);

  if (!match) {
    throw new Error(`Satır formatı hatalı: ${line}. Örnek: 1 Cem`);
  }

  return `${match[1]} ${match[2]}`;
});

return [{
  json: {
    ok: true,
    sourceChatId,
    players,
    caption: 'Maç öncesi ilk 11 🔥',
    cloudName: 'dedg2waka',
    uploadPreset: 'n8n_unsigned',
    templatePublicId: 'Template_ss2jag',
    startY: 640,
    stepY: 130,
    fontSize: 66,
    textColor: 'FFFFFF',
    strokeColor: '7A1FFF',
    folder: 'ilk11-final'
  }
}];

const data = $input.first().json;

function encText(s) {
  return encodeURIComponent(s)
    .replace(/%20/g, '%20')
    .replace(/,/g, '%2C')
    .replace(/\//g, '%2F');
}

const overlays = data.players.flatMap((player, i) => {
  const y = data.startY + (i * data.stepY);

  const match = player.match(/^(\d{1,2})\s+(.+)$/);
  const number = match ? match[1] : '';
  const name = match ? match[2] : player;

  const num = encText(number);
  const nam = encText(name);

  return [
    // Number glow
    [
      `l_text:Arial_${Math.round(data.fontSize * 1.9)}_bold:${num}`,
      `co_rgb:B55CFF`,
      `g_north_west`,
      `x_690`,
      `y_${y - 30}`
    ].join(','),

    // Number main
    [
      `l_text:Arial_${Math.round(data.fontSize * 1.9)}_bold:${num}`,
      `co_rgb:E9D5FF`,
      `g_north_west`,
      `x_686`,
      `y_${y - 30}`
    ].join(','),

    // Name glow
    [
      `l_text:Arial_${Math.round(data.fontSize * 1.9)}_bold:${nam}`,
      `co_rgb:B55CFF`,
      `g_north_west`,
      `x_870`,
      `y_${y - 30}`
    ].join(','),

    // Name main
    [
      `l_text:Arial_${Math.round(data.fontSize * 1.9)}_bold:${nam}`,
      `co_rgb:E9D5FF`,
      `g_north_west`,
      `x_866`,
      `y_${y - 30}`
    ].join(',')
  ];
}).join('/');

const transformedUrl = `https://res.cloudinary.com/${data.cloudName}/image/upload/${overlays}/${data.templatePublicId}.jpg`;

return [{
  json: {
    ...data,
    transformedUrl
  }
}];

const msg = $input.first().json.message;
const text = (msg.text || '').trim();
const sourceChatId = msg.chat.id;

if (!text.startsWith('/sonuc ')) {
  return [{
    json: {
      ok: false,
      reason: 'Komut /sonuc ile başlamalı. Örnek: /sonuc 5-1 Bababalar Spor',
      sourceChatId
    }
  }];
}

const commandBody = text.replace('/sonuc', '').trim();
const parts = commandBody.split(' ');

if (parts.length < 2) {
  return [{
    json: {
      ok: false,
      reason: 'Format hatalı. Örnek: /sonuc 5-1 Bababalar Spor',
      sourceChatId
    }
  }];
}

const scorePart = parts[0];
const rivalName = parts.slice(1).join(' ').trim();

const scoreMatch = scorePart.match(/^(\d+)-(\d+)$/);

if (!scoreMatch) {
  return [{
    json: {
      ok: false,
      reason: 'Skor formatı hatalı. Örnek: /sonuc 5-1 Bababalar Spor',
      sourceChatId
    }
  }];
}

const homeScore = scoreMatch[1];
const awayScore = scoreMatch[2];

return [{
  json: {
    ok: true,
    sourceChatId,
    homeScore,
    awayScore,
    rivalName,
    caption: `Maç sonucu 🔥\n\n${homeScore}-${awayScore}\nRakip: ${rivalName}`,
    cloudName: 'dedg2waka',
    uploadPreset: 'n8n_unsigned',
    templatePublicId: 'mac_sonucu_lsmoll',
    folder: 'mac-sonucu-final',
    scoreFontSize: 170,
    rivalFontSize: 110,
    textColor: 'E9D5FF',
    glowColor: 'B55CFF'
  }
}];

