    `co_rgb:${data.glowColor}`,
    `g_center`,
    `x_742`,
    `y_-10`
  ].join(','),

  [
    `l_text:Arial_${data.scoreFontSize}_bold:${away}`,
    `co_rgb:${data.textColor}`,
    `g_center`,
    `x_737`,
    `y_-15`
  ].join(','),

  // RAKİP - glow (kutunun merkezine göre ortalı)
  [
    `l_text:Arial_${data.rivalFontSize}_bold:${rival}`,
    `co_rgb:${data.glowColor}`,
